// PUT — полная замена объекта
// PATCH — частичное обновление
const updateUser = async (id, data) => {
    const response = await fetch(`https://api.example.com/users/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
    });
    return response.json();
};
```

### DELETE (удалить)
```javascript
const deleteUser = async (id) => {
    await fetch(`https://api.example.com/users/${id}`, {
        method: 'DELETE',
    });
};
```

## JSON — формат данных

```javascript
// Объект → строка (для отправки)
const str = JSON.stringify({ name: 'Иван', age: 25 });
// '{"name":"Иван","age":25}'

// Строка → объект (после получения)
const obj = JSON.parse('{"name":"Иван","age":25}');
// { name: 'Иван', age: 25 }

// Красивый вывод в консоль
console.log(JSON.stringify(data, null, 2));
```

## Практика: Загрузка и отображение постов

```javascript
const renderPosts = async () => {
    const container = document.querySelector('.posts');

    // Показать индикатор загрузки
    container.innerHTML = '<p>Загрузка...</p>';

    try {
        const response = await fetch('https://jsonplaceholder.typicode.com/posts?_limit=5');
        const posts = await response.json();

        // Отрисовать посты
        container.innerHTML = posts
            .map(post => `
                <article class="post">
                    <h2>${post.title}</h2>
                    <p>${post.body}</p>
                </article>
            `)
            .join('');
    } catch (error) {
        container.innerHTML = '<p class="error">Не удалось загрузить данные</p>';
    }
};

renderPosts();
```

**jsonplaceholder.typicode.com** — бесплатный тестовый API для практики.

## Параллельные запросы
```javascript
// Дождаться всех запросов одновременно
const [users, posts] = await Promise.all([
    fetch('/api/users').then(r => r.json()),
    fetch('/api/posts').then(r => r.json()),
]);
```

content.newText:
JavaScript — **однопоточный**. Пока выполняется одна операция, остальные ждут. Асинхронность позволяет "не блокировать" поток во время ожидания (данных с сервера, таймера, файла).

## Промис (Promise)
Объект, который представляет **будущее значение** — операцию, которая ещё не завершена.

```
Promise находится в одном из трёх состояний:
- pending   (ожидание) — операция ещё идёт
- fulfilled (выполнен) — успех, есть результат
- rejected  (отклонён) — ошибка
```

### Создание промиса
```javascript
const myPromise = new Promise((resolve, reject) => {
    // Имитация задержки (например, запрос к API)
    setTimeout(() => {
        const success = true;

        if (success) {
            resolve('Данные получены!'); // Успех
        } else {
            reject(new Error('Что-то пошло не так')); // Ошибка
        }
    }, 1000);
});
```

### Обработка промиса через `.then/.catch`
```javascript
myPromise
    .then(result => console.log(result))     // 'Данные получены!'
    .catch(error => console.error(error))    // Если rejected
    .finally(() => console.log('Готово!'));  // Всегда выполняется
```

## Async / Await — синтаксический сахар над промисами ⭐

`async/await` делает асинхронный код похожим на синхронный:

```javascript
// С промисами (цепочки сложнее читать)
fetch('/api/user')
    .then(res => res.json())
    .then(user => fetch(`/api/posts?userId=${user.id}`))
    .then(res => res.json())
    .then(posts => console.log(posts));

// С async/await (читается как обычный код)
const loadUserPosts = async () => {
    const userRes = await fetch('/api/user');
    const user = await userRes.json();

    const postsRes = await fetch(`/api/posts?userId=${user.id}`);
    const posts = await postsRes.json();

    console.log(posts);
};
```

**Правила:**
*   `await` можно использовать только внутри `async`-функции.
*   `async`-функция всегда возвращает промис.

## Обработка ошибок

### try / catch / finally
```javascript
const loadData = async () => {
    try {
        const response = await fetch('/api/data');

        if (!response.ok) {
            throw new Error(`Сервер вернул ${response.status}`);
        }

        const data = await response.json();
        return data;

    } catch (error) {
        // Сетевая ошибка или ошибка из throw
        console.error('Ошибка:', error.message);
        return null;

    } finally {
        // Выполнится всегда — например скрыть спиннер
        hideSpinner();
    }
};
```

## Promise.all — параллельное выполнение
```javascript
// Запросы выполняются ПАРАЛЛЕЛЬНО — быстрее!
const [users, categories] = await Promise.all([
    fetch('/api/users').then(r => r.json()),
    fetch('/api/categories').then(r => r.json()),
]);

// ЕСЛИ ОДИН УПАДЁТ — упадут все. Для независимых запросов:
const results = await Promise.allSettled([
    fetch('/api/users').then(r => r.json()),
    fetch('/api/broken-endpoint').then(r => r.json()),
]);
// results[0].status = 'fulfilled', results[0].value = [...]
// results[1].status = 'rejected', results[1].reason = Error
```

## Типичные паттерны

### Состояния загрузки
```javascript
let isLoading = false;
let error = null;
let data = null;

const fetchData = async () => {
    isLoading = true;
    error = null;
    render(); // Обновить UI

    try {
        data = await fetchUsers();
    } catch (err) {
        error = err.message;
    } finally {
        isLoading = false;
        render(); // Обновить UI
    }
};
```

### Функция с повторными попытками
```javascript
const fetchWithRetry = async (url, retries = 3) => {
    for (let i = 0; i < retries; i++) {
        try {
            const res = await fetch(url);
            if (res.ok) return res.json();
            throw new Error(`HTTP ${res.status}`);
        } catch (err) {
            if (i === retries - 1) throw err; // Последняя попытка — пробросить ошибку
            await new Promise(r => setTimeout(r, 1000 * (i + 1))); // Задержка
        }
    }
};
```

