Собираем всё вместе. Делаем приложение **Список задач (Todo App)** — классический проект для закрепления основ React.

## Что умеет приложение
*   Добавлять задачи
*   Отмечать задачи выполненными
*   Удалять задачи
*   Фильтровать (все / активные / выполненные)
*   Сохранять в LocalStorage

## Структура
```
src/
├── App.jsx
├── components/
│   ├── TodoForm.jsx     — форма добавления
│   ├── TodoList.jsx     — список задач
│   ├── TodoItem.jsx     — одна задача
│   └── TodoFilter.jsx  — фильтр
└── main.jsx
```

## App.jsx — главный компонент
```jsx
import { useState, useEffect } from 'react';
import TodoForm from './components/TodoForm';
import TodoList from './components/TodoList';
import TodoFilter from './components/TodoFilter';

const App = () => {
    const [todos, setTodos] = useState(() => {
        // Загрузить из LocalStorage при инициализации
        const saved = localStorage.getItem('todos');
        return saved ? JSON.parse(saved) : [];
    });
    const [filter, setFilter] = useState('all'); // 'all' | 'active' | 'done'

    // Сохранять при каждом изменении
    useEffect(() => {
        localStorage.setItem('todos', JSON.stringify(todos));
    }, [todos]);

    const addTodo = (text) => {
        setTodos(prev => [...prev, { id: Date.now(), text, done: false }]);
    };

    const toggleTodo = (id) => {
        setTodos(prev =>
            prev.map(todo =>
                todo.id === id ? { ...todo, done: !todo.done } : todo
            )
        );
    };

    const deleteTodo = (id) => {
        setTodos(prev => prev.filter(todo => todo.id !== id));
    };

    // Фильтрация
    const filteredTodos = todos.filter(todo => {
        if (filter === 'active') return !todo.done;
        if (filter === 'done') return todo.done;
        return true;
    });

    return (
        <div className="app">
            <h1>Список задач</h1>
            <TodoForm onAdd={addTodo} />
            <TodoFilter current={filter} onChange={setFilter} />
            <TodoList
                todos={filteredTodos}
                onToggle={toggleTodo}
                onDelete={deleteTodo}
            />
            <p>{todos.filter(t => !t.done).length} задач осталось</p>
        </div>
    );
};

export default App;
```

## TodoForm.jsx
```jsx
import { useState } from 'react';

const TodoForm = ({ onAdd }) => {
    const [text, setText] = useState('');

    const handleSubmit = (e) => {
        e.preventDefault();
        if (!text.trim()) return; // Не добавлять пустые
        onAdd(text.trim());
        setText(''); // Очистить поле
    };

    return (
        <form onSubmit={handleSubmit} className="todo-form">
            <input
                type="text"
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Новая задача..."
                autoFocus
            />
            <button type="submit" disabled={!text.trim()}>
                Добавить
            </button>
        </form>
    );
};

export default TodoForm;
```

## TodoItem.jsx
```jsx
const TodoItem = ({ todo, onToggle, onDelete }) => (
    <li className={`todo-item ${todo.done ? 'todo-item--done' : ''}`}>
        <input
            type="checkbox"
            checked={todo.done}
            onChange={() => onToggle(todo.id)}
        />
        <span className="todo-item__text">{todo.text}</span>
        <button
            className="todo-item__delete"
            onClick={() => onDelete(todo.id)}
            aria-label="Удалить задачу"
        >
            ×
        </button>
    </li>
);

export default TodoItem;
```

## TodoList.jsx
```jsx
import TodoItem from './TodoItem';

const TodoList = ({ todos, onToggle, onDelete }) => {
    if (todos.length === 0) {
        return <p className="empty">Задач нет. Отдыхай!</p>;
    }

    return (
        <ul className="todo-list">
            {todos.map(todo => (
                <TodoItem
                    key={todo.id}
                    todo={todo}
                    onToggle={onToggle}
                    onDelete={onDelete}
                />
            ))}
        </ul>
    );
};

export default TodoList;
```

## TodoFilter.jsx
```jsx
const FILTERS = [
    { value: 'all', label: 'Все' },
    { value: 'active', label: 'Активные' },
    { value: 'done', label: 'Выполненные' },
];

const TodoFilter = ({ current, onChange }) => (
    <div className="todo-filter">
        {FILTERS.map(({ value, label }) => (
            <button
                key={value}
                className={`filter-btn ${current === value ? 'filter-btn--active' : ''}`}
                onClick={() => onChange(value)}
            >
                {label}
            </button>
        ))}
    </div>
);

export default TodoFilter;
```

## Что дальше
После Todo App изучи:
*   **React Router** — навигация между страницами
*   **useContext** — глобальное состояние без пропс-дриллинга
*   **useReducer** — управление сложным состоянием
*   **Redux Toolkit** — стейт-менеджмент для крупных приложений
*   **React Query / SWR** — удобная работа с серверными данными

