cat > /tmp/read_md4.ps1 << 'PSEOF'
$basePath = 'D:\Local DB HP\Frontender 1.0'
$validPrefixes = @('01','02','03','04','05','06','07','08')
$outFile = 'D:\Local DB HP\md_final.txt'
$writer = [System.IO.StreamWriter]::new($outFile, $false, [System.Text.Encoding]::UTF8)

Get-ChildItem -Path $basePath -Recurse -Filter '*.md' | Where-Object {
    $parts = $_.FullName.Replace($basePath, '').TrimStart('\').Split('\')
    if ($parts.Count -ge 1) {
        $folderPrefix = $parts[0].Substring(0, [Math]::Min(2, $parts[0].Length))
        $validPrefixes -contains $folderPrefix
