    $writer.WriteLine('=== FILE: ' + $_.FullName + ' ===')
    $lines = [System.IO.File]::ReadAllLines($_.FullName, [System.Text.Encoding]::UTF8)
    foreach ($line in $lines) {
        $writer.WriteLine($line)
    }
    $writer.WriteLine('---END---')
}
$writer.Close()
